// Setup: read env vars + merge with webhook input
const body = $input.first().json.body || $input.first().json;

const tenantId = $env.MS_GRAPH_TENANT_ID;
const clientId = $env.MS_GRAPH_CLIENT_ID;
const clientSecret = $env.MS_GRAPH_CLIENT_SECRET;
const driveId = $env.SHAREPOINT_DRIVE_ID;
const proposalsFolderId = $env.SHAREPOINT_PROPOSALS_FOLDER_ID;
const leadsTrackerFileId = $env.LEADS_TRACKER_FILE_ID;
const kbFileId = $env.SHAREPOINT_KB_FILE_ID;
const aoaiEndpoint = $env.AZURE_OPENAI_ENDPOINT;
const aoaiDeployment = $env.AZURE_OPENAI_CHAT_DEPLOYMENT;
const aoaiApiVersion = $env.AZURE_OPENAI_API_VERSION;
const mailUserUpn = $env.MAIL_USER_UPN;

return [{
  json: {
    tenantId, clientId, clientSecret, driveId,
    proposalsFolderId, leadsTrackerFileId, kbFileId,
    aoaiEndpoint, aoaiDeployment, aoaiApiVersion,
    mailUserUpn,
    lead: {
      leadId: body.leadId || `LEAD-${Date.now()}`,
      firstName: body.firstName || '',
      lastName: body.lastName || '',
      email: body.email || '',
      phone: body.phone || '',
      company: body.company || '',
      eventDate: body.eventDate || 'TBD',
      guestCount: body.guestCount || '',
      budget: body.budget || '',
      hasVenue: body.hasVenue || '',
      venueName: body.venueName || '',
      menuTier: body.menuTier || body.suggestedMenuTier || 'Standard',
      qualificationNotes: body.qualificationNotes || '',
      isNonProfit: body.isNonProfit || body.nonprofit || 'No'
    }
  }
}];

// Save the access token and pass through setup vars, then prepare KB download URL
const setup = $('Setup Variables').first().json;
const tokenResp = $input.first().json;
const accessToken = tokenResp.access_token;
const driveId = setup.driveId;
const kbFileId = setup.kbFileId;

// Build the Graph API URL to download KB file content
const kbDownloadUrl = `https://graph.microsoft.com/v1.0/drives/${driveId}/items/${kbFileId}/content`;

return [{
  json: {
    ...setup,
    accessToken,
    kbDownloadUrl
  }
}];

// Build AI proposal generation prompt — grounded in Knowledge Base
const setup = $('Prepare KB Download').first().json;
const kbContent = $input.first().json.data || $input.first().json;
const lead = setup.lead;

// The KB download returns the raw markdown text
let knowledgeBase = '';
if (typeof kbContent === 'string') {
  knowledgeBase = kbContent;
} else if (kbContent.data && typeof kbContent.data === 'string') {
  knowledgeBase = kbContent.data;
} else {
  // Fallback: stringify whatever we got
  knowledgeBase = JSON.stringify(kbContent);
}

const systemPrompt = `You are a professional proposal writer for Executive Catering CT. You write formal, detailed catering proposals that are STRICTLY grounded in the company's official knowledge base.

=== KNOWLEDGE BASE (AUTHORITATIVE SOURCE) ===
${knowledgeBase}
=== END KNOWLEDGE BASE ===

CRITICAL RULES:
1. You must ONLY include menu items, flavors, sides, beverages, and services that appear in the Knowledge Base above.
2. Do NOT invent, fabricate, or hallucinate any food items, flavors, pricing, or services not listed in the Knowledge Base.
3. Use the exact item names, descriptions, and catering sizes from the Knowledge Base.
4. Pricing tiers and per-person ranges must match the Knowledge Base exactly.
5. Staffing levels, equipment, terms, and policies must come directly from the Knowledge Base.
6. If the client requests something not in the Knowledge Base, note it as a \"custom request requiring consultation\" — do not make up items to fill the gap.
7. The 10% non-profit discount applies only to verified 501(c)(3) organizations as stated in the Knowledge Base.
8. Proposal validity, deposit, cancellation, and headcount policies must match the Knowledge Base exactly.

Generate a complete catering proposal based on the lead information provided. The proposal should be professional, warm, and detailed.

Return a JSON object with this exact structure:
{
  "companyIntro": "<2-3 paragraph company introduction highlighting Executive Catering CT's experience and commitment to excellence, referencing Wallingford CT location and 1 Stop Wings heritage>",
  "eventSummary": "<paragraph summarizing the client's event needs as we understand them>",
  "menuOptions": [
    {
      "tierName": "<tier name from Knowledge Base: Budget, Standard, Premium, or Luxury>",
      "description": "<brief tier description matching the Knowledge Base>",
      "items": [
        {
          "category": "<category from KB: Wings & Tenders, Sandwich Platters, Soup, Slow-Roasted Ribs, Salads, Sides & Extras, Beverages, Breakfast Catering>",
          "name": "<exact item name from KB>",
          "quantity": "<catering size from KB, e.g. 'Tray of 100', 'Full Tray (serves 20)'>",
          "flavor": "<if applicable, exact flavor from KB list>",
          "notes": "<any relevant detail>"
        }
      ],
      "pricePerPerson": "<dollar range from the KB tier>"
    }
  ],
  "staffingPlan": "<staffing description using exact service levels and ratios from the Knowledge Base>",
  "equipmentAndRentals": "<equipment details from the Knowledge Base, matching what's included at the proposed tier>",
  "timeline": [
    { "time": "<time from KB Event Timeline>", "activity": "<activity from KB>" }
  ],
  "pricingSummary": {
    "foodAndBeverage": "<estimate based on KB tier pricing x guest count>",
    "staffing": "<estimate based on KB staffing ratios>",
    "equipmentRentals": "<from KB: included or additional cost>",
    "deliveryAndSetup": "<from KB: included within 30mi or $2/mi beyond>",
    "serviceCharge": "<20% for Full Service/Luxury per KB, or N/A>",
    "nonProfitDiscount": "<10% if applicable per KB, otherwise 'N/A'>",
    "estimatedTotal": "<calculated total range>",
    "depositRequired": "<50% per KB terms>"
  },
  "terms": "<use the exact terms from the Knowledge Base: 50% deposit, final payment 5 business days before, 7-day headcount lock, cancellation tiers (14+ days/7-13 days/<7 days), 30-day proposal validity>"
}

Provide 2-3 menu options appropriate for the indicated tier. Every item must exist in the Knowledge Base.`;

const userPrompt = `Generate a catering proposal for this event:

Client: ${lead.firstName} ${lead.lastName}
Company: ${lead.company || 'Private Event'}
Non-Profit: ${lead.isNonProfit}
Event Date: ${lead.eventDate}
Guest Count: ${lead.guestCount}
Budget Range: ${lead.budget}
Venue: ${lead.venueName || (lead.hasVenue === 'Yes' ? 'Client venue (name TBD)' : 'Venue not yet secured')}
Suggested Menu Tier: ${lead.menuTier}
Additional Context: ${lead.qualificationNotes || 'None'}`;

return [{
  json: {
    ...setup,
    lead,
    aoaiBody: {
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      max_completion_tokens: 4000,
      response_format: { type: 'json_object' }
    }
  }
}];

// Parse AI response and prepare data for DOCX generation
const prev = $('Build AI Proposal Prompt').first().json;
const aiResp = $input.first().json;
const lead = prev.lead;

let proposal;
try {
  proposal = JSON.parse(aiResp.choices[0].message.content);
} catch (e) {
  throw new Error(`Failed to parse AI proposal: ${e.message}`);
}

const safeDate = (lead.eventDate || 'TBD').replace(/[^a-zA-Z0-9-]/g, '_');
const safeName = (lead.lastName || 'Client').replace(/[^a-zA-Z0-9]/g, '_');
const filename = `Proposal_${safeName}_${safeDate}.docx`;

return [{
  json: {
    accessToken: prev.accessToken,
    driveId: prev.driveId,
    proposalsFolderId: prev.proposalsFolderId,
    leadsTrackerFileId: prev.leadsTrackerFileId,
    lead,
    proposal,
    filename,
    leadId: lead.leadId
  }
}];

// Finalize: build webhook response from upload result
const uploadResp = $input.first().json;
const prev = $('Prepare Proposal Data').first().json;

return [{
  json: {
    status: 'proposal_generated',
    leadId: prev.leadId,
    filename: uploadResp.filename || prev.filename,
    sharePointUrl: uploadResp.sharePointUrl || '',
    docxSizeBytes: uploadResp.sizeBytes || 0,
    generatedAt: new Date().toISOString(),
    message: 'Proposal generated and saved to SharePoint Proposals folder (grounded in Knowledge Base)'
  }
}];
